package org.eclipse.rdf4j.sail.lmdb.estimation;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.time.Duration;
import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import java.util.concurrent.atomic.AtomicInteger;

import org.junit.jupiter.api.Test;

class QuadSynopsisTest {

	private static final long MIB = 1024L * 1024L;
	private static final QuadSnapshotIdentity IDENTITY = new QuadSnapshotIdentity(17L, 23L, 5L);

	@Test
	void probeValidatesMasksAndBoundIds() {
		assertThrows(IllegalArgumentException.class,
				() -> new QuadProbe(16, 0, 1L, 0L, 0L, 0L, IDENTITY));
		assertThrows(IllegalArgumentException.class,
				() -> new QuadProbe(QuadProbe.SUBJECT, 0, 0L, 0L, 0L, 0L, IDENTITY));
		QuadProbe probe = new QuadProbe(QuadProbe.SUBJECT | QuadProbe.PREDICATE, QuadProbe.OBJECT,
				1L, 2L, 0L, 0L, IDENTITY);
		assertTrue(probe.isBound(QuadProbe.SUBJECT));
		assertFalse(probe.isBound(QuadProbe.OBJECT));
		assertEquals(QuadHash.conditioningKey(probe.boundMask(), 1L, 2L, 0L, 0L), probe.conditioningKey());
	}

	@Test
	void primitiveCountMinIsMonotoneAndNeverUnderCounts() {
		PrimitiveCountMin table = new PrimitiveCountMin(4, 1024, 31L);
		table.add(11L, 3L);
		table.add(19L, 5L);
		table.add(11L, 2L);
		assertTrue(table.estimate(11L) >= 5L);
		assertTrue(table.estimate(19L) >= 5L);
		assertEquals(0L, table.estimate(99L));
		assertEquals(4L * 1024L * Long.BYTES, table.allocatedBytes());
	}

	@Test
	void primitiveSpaceSavingRetainsHeavyKeysWithinFixedStorage() {
		PrimitiveSpaceSaving directory = new PrimitiveSpaceSaving(8);
		for (int round = 0; round < 100; round++) {
			for (int repeat = 0; repeat < 10; repeat++) {
				directory.offer(1L, 1L);
				directory.offer(2L, 1L);
			}
			for (long key = 10L; key < 30L; key++) {
				directory.offer(key + round * 100L, 1L);
			}
		}
		assertTrue(directory.contains(1L));
		assertTrue(directory.contains(2L));
		assertTrue(directory.estimate(1L) >= 1_000L);
		assertEquals(8, directory.capacity());
		assertTrue(directory.allocatedBytes() < 2048L);
	}

	@Test
	void bottomKIsOrderIndependentAndUsesContiguousStorage() {
		List<long[]> rows = rows();
		PrimitiveBottomK forward = new PrimitiveBottomK(3);
		PrimitiveBottomK reverse = new PrimitiveBottomK(3);
		for (long[] row : rows) {
			forward.offer(row[0], row[1], row[2], row[3]);
		}
		Collections.reverse(rows);
		for (long[] row : rows) {
			reverse.offer(row[0], row[1], row[2], row[3]);
		}
		assertEquals(forward, reverse);
		assertEquals(3, forward.size());
		assertEquals(3L * 5L * Long.BYTES, forward.allocatedBytes());
	}

	@Test
	void equivalentPrimitiveDistributionSketchesHaveSemanticEquality() {
		PrimitiveBottomK.ProjectionSample firstSample = new PrimitiveBottomK.ProjectionSample(
				new long[] { 11L, 11L, 23L }, 3, 3, 3);
		PrimitiveBottomK.ProjectionSample equivalentSample = new PrimitiveBottomK.ProjectionSample(
				new long[] { 11L, 11L, 23L }, 3, 3, 3);
		PrimitiveDistributionSketch first = PrimitiveDistributionSketch.from(firstSample, 3.0d, true);
		PrimitiveDistributionSketch equivalent = PrimitiveDistributionSketch.from(equivalentSample, 3.0d, true);

		assertEquals(first, equivalent,
				"Memo evidence identity must depend on the distribution, not the sketch allocation");
		assertEquals(first.hashCode(), equivalent.hashCode());
	}

	@Test
	void synopsisAnswersEveryBoundShapeWithoutFalseNegativeZeros() {
		QuadSynopsisBudget budget = QuadSynopsisBudget.create(16L * MIB, 64);
		QuadSynopsisSnapshot snapshot = build(budget, rows());
		BoundedQuadSynopsis synopsis = new BoundedQuadSynopsis(snapshot, budget, () -> {
		});

		assertRows(synopsis, new QuadProbe(0, 0, 0L, 0L, 0L, 0L, IDENTITY), 5.0d);
		assertRows(synopsis, new QuadProbe(QuadProbe.SUBJECT, QuadProbe.OBJECT,
				1L, 0L, 0L, 0L, IDENTITY), 2.0d);
		assertRows(synopsis, new QuadProbe(QuadProbe.PREDICATE, QuadProbe.SUBJECT | QuadProbe.OBJECT,
				0L, 10L, 0L, 0L, IDENTITY), 4.0d);
		assertRows(synopsis, new QuadProbe(QuadProbe.OBJECT | QuadProbe.CONTEXT, QuadProbe.SUBJECT,
				0L, 0L, 100L, 1L, IDENTITY), 1.0d);

		QuadEvidence missing = synopsis.probe(new QuadProbe(QuadProbe.SUBJECT, 0,
				999L, 0L, 0L, 0L, IDENTITY));
		assertEquals(0.0d, missing.rows().estimate());
		assertTrue(missing.rows().exactZero());
		assertTrue(missing.usable());

		QuadEvidence projected = synopsis.probe(new QuadProbe(QuadProbe.SUBJECT, QuadProbe.OBJECT,
				1L, 0L, 0L, 0L, IDENTITY));
		assertTrue(projected.distribution().isPresent());
		assertEquals(2.0d, projected.distribution().orElseThrow().distinctRows());
	}

	@Test
	void snapshotBuildIsIndependentOfStatementOrder() {
		QuadSynopsisBudget budget = QuadSynopsisBudget.create(8L * MIB, 32);
		List<long[]> forwardRows = rows();
		List<long[]> reverseRows = new ArrayList<>(forwardRows);
		Collections.reverse(reverseRows);
		QuadSynopsisSnapshot forward = build(budget, forwardRows);
		QuadSynopsisSnapshot reverse = build(budget, reverseRows);
		for (int mask = 0; mask < 16; mask++) {
			long[] row = forwardRows.getFirst();
			QuadProbe probe = new QuadProbe(mask, (~mask) & 15, row[0], row[1], row[2], row[3], IDENTITY);
			assertEquals(forward.probe(probe).rows().estimate(), reverse.probe(probe).rows().estimate());
		}
		assertEquals(forward.coldSample(), reverse.coldSample());
	}

	@Test
	void repeatedComponentConstraintsAreEstimatedFromFullRowWitnesses() {
		QuadSynopsisBudget budget = QuadSynopsisBudget.create(8L * MIB, 32);
		List<long[]> repeatedRows = List.of(
				new long[] { 1L, 10L, 1L, 0L },
				new long[] { 2L, 10L, 3L, 0L },
				new long[] { 4L, 11L, 4L, 1L });
		BoundedQuadSynopsis synopsis = new BoundedQuadSynopsis(build(budget, repeatedRows), budget, () -> {
		});
		long equalityGroup = QuadProbe.equalityToken(1);

		assertRows(synopsis, new QuadProbe(0, QuadProbe.SUBJECT | QuadProbe.OBJECT,
				equalityGroup, 0L, equalityGroup, 0L, IDENTITY), 2.0d);
		assertRows(synopsis, new QuadProbe(QuadProbe.PREDICATE, QuadProbe.SUBJECT | QuadProbe.OBJECT,
				equalityGroup, 10L, equalityGroup, 0L, IDENTITY), 1.0d);
	}

	@Test
	void additionsStayBoundedAndDeletionInvalidatesUntilRebuild() {
		QuadSynopsisBudget budget = QuadSynopsisBudget.create(16L * MIB, 32);
		AtomicInteger rebuildRequests = new AtomicInteger();
		BoundedQuadSynopsis synopsis = new BoundedQuadSynopsis(build(budget, rows()), budget,
				rebuildRequests::incrementAndGet);

		for (int i = 0; i < 10_000; i++) {
			synopsis.add(1000L + i, 20L, 200L + (i & 31), 0L);
		}
		assertTrue(synopsis.allocatedBytes() <= budget.totalBytes());
		assertTrue(synopsis.probe(new QuadProbe(QuadProbe.PREDICATE, 0,
				0L, 20L, 0L, 0L, IDENTITY)).rows().estimate() >= 10_000.0d);

		synopsis.delete(1L, 10L, 100L, 0L);
		assertFalse(synopsis.probe(new QuadProbe(0, 0, 0L, 0L, 0L, 0L, IDENTITY)).usable());
		assertEquals(1, rebuildRequests.get());
	}

	@Test
	void millionIncrementalRowsRemainInsideConfiguredBudget() {
		org.junit.jupiter.api.Assertions.assertTimeoutPreemptively(Duration.ofSeconds(20), () -> {
			QuadSynopsisBudget budget = QuadSynopsisBudget.create(32L * MIB, 128);
			BoundedQuadSynopsis synopsis = new BoundedQuadSynopsis(build(budget, List.of()), budget, () -> {
			});
			for (int i = 0; i < 1_000_000; i++) {
				synopsis.add(i + 1L, 10L + i % 97L, 100L + i % 10_007L, i & 3L);
			}
			assertTrue(synopsis.allocatedBytes() <= budget.totalBytes());
			assertEquals(1_000_000.0d, synopsis.probe(
					new QuadProbe(0, 0, 0L, 0L, 0L, 0L, IDENTITY)).rows().estimate());
		});
	}

	private static QuadSynopsisSnapshot build(QuadSynopsisBudget budget, List<long[]> rows) {
		QuadSynopsisBuilder builder = new QuadSynopsisBuilder(budget, IDENTITY, 7L);
		for (long[] row : rows) {
			builder.add(row[0], row[1], row[2], row[3]);
		}
		return builder.build();
	}

	private static void assertRows(BoundedQuadSynopsis synopsis, QuadProbe probe, double expected) {
		QuadEvidence evidence = synopsis.probe(probe);
		assertTrue(evidence.usable());
		assertTrue(evidence.rows().lowerBound() <= expected);
		assertTrue(evidence.rows().upperBound() >= expected);
		assertEquals(expected, evidence.rows().estimate());
	}

	private static List<long[]> rows() {
		List<long[]> rows = new ArrayList<>();
		rows.add(new long[] { 1L, 10L, 100L, 0L });
		rows.add(new long[] { 1L, 10L, 101L, 0L });
		rows.add(new long[] { 2L, 10L, 100L, 1L });
		rows.add(new long[] { 3L, 10L, 102L, 1L });
		rows.add(new long[] { 3L, 11L, 100L, 0L });
		return rows;
	}
}
